function parseS3Upload(s3Upload) {
  const key = s3Upload['Key'];

  let contentType;

  if (key === 'file1') contentType = 'image/png';
  else if (key === 'file2.txt') contentType = 'text/plain'
  
  return {
    Body: s3Upload, 
    ContentType: contentType 
  }
}


exports.handler = async(event) => {
  const body = parseS3Upload(JSON.parse(event['body']));

  let response;  // Response
  if (body === undefined){
    response = {
      statusCode: 401, 
      statusMessage:"Invalid request" 
    }; 
  } else{
	const params = {
	  Bucket:'uploads-bucket-for-aws-assignment', 
	  Key:`uploaded-files/${event['path']}`, 
	  Body : body.Body , 
	  ContentType : body.ContentType  
	}
    const s3PutParams = await new AWS.S3({params}).putObject(params).promise();  // Code will only reach this line once params has been used to call the API
    
    console.log(`Successfully uploaded ${key}`); 
    response={
      statusCode:200, 
      statusMessage:'Ok',
    }

  }
  return response;
}